+fn planner_promote_ipk_equality_terms(
+    where_terms: &mut [fsqlite_planner::WhereTerm<'_>],
+    table_name: &str,
+    table_alias: Option<&str>,
+    ipk_column_name: &str,
+) -> bool {
+    let mut promoted = false;
+    for term in where_terms {
+        if !matches!(term.kind, WhereTermKind::Equality) {
+            continue;
+        }
+        let matches_ipk = term.column.as_ref().is_some_and(|column| {
+            planner_where_column_matches(column, table_name, table_alias, ipk_column_name)
+        });
+        if matches_ipk {
+            term.kind = WhereTermKind::RowidEquality;
+            promoted = true;
+        }
+    }
+    promoted
