+    #[test]
+    fn test_planner_select_directive_ipk_equality_with_table_alias_uses_rowid_lookup() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE plan_ipk_alias (id INTEGER PRIMARY KEY, val TEXT);")
+            .unwrap();
+
+        let select =
+            parse_select_statement("SELECT p.val FROM plan_ipk_alias AS p WHERE p.id = ?1");
+        let schema = conn.schema.borrow();
+        let directive = Connection::planner_select_directive(&select, &schema)
+            .expect("IPK equality with table alias should produce a planner directive");
+
+        assert_eq!(directive.access_kind, PlannerSelectAccessKind::RowidLookup);
+    }
